head.script:
scwin.sUserId = "";
scwin.sUserClsCd = "";
scwin.sClntNo = "";
scwin.sClntNm = "";
scwin.sLobranCd = "";
scwin.strlobranCd = "";
scwin.strlobranNm = "";
scwin.strFromDate = "";
scwin.hid_adptDt = "";
scwin.hid_con_usblDt = "";

scwin.onpageload = function() {
    scwin.sUserId = $c.ses.getUserId();
    scwin.sUserClsCd = $c.ses.getUserClsCd();
    scwin.sClntNo = $c.ses.getClntNo();
    scwin.sClntNm = $c.ses.getClntNm();
    scwin.sLobranCd = $c.ses.getLoUpperLobranCd();

    let params = $c.data.getParameter();
    if (params != null) {
        scwin.strlobranCd = params["strlobranCd"] || "";
        scwin.strlobranNm = params["strlobranNm"] || "";
    }

    scwin.strFromDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");

    lc_wrkPlCd.removeAll();
    lc_wrkPlCd.addItem("기흥창고", "4W05");
    lc_wrkPlCd.addItem("오류창고", "1W04");
    lc_wrkPlCd.addItem("광주창고", "5W01");
    lc_wrkPlCd.setSelectedIndex(0);
};

scwin.onUdcCompleted = function() {
    ed_adptDt.setValue(scwin.strFromDate);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.f_Retrieve = async function() {
    if (ed_adptDt.getValue() == "" || ed_adptDt.getValue().length < 8) {
        await $c.win.alert("기준일자를 정확하게 입력하여 주세요.");
        ed_adptDt.setFocus();
        return;
    }

    if (lc_wrkPlCd.getValue() == "") {
        await $c.win.alert("작업장을 선택하여 주시기 바랍니다.");
        lc_wrkPlCd.setFocus();
        return;
    }

    await $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowCnt = ds_Present.getRowCount();
    if (rowCnt == 0) {
        await $c.win.alert("조회된 데이터가 없습니다.");
    }
    spa_totalRow.setValue(ds_Present.getRowCount());
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_AddRow = function() {
    $c.data.insertRow(ds_Present);
    spa_totalRow.setValue(ds_Present.getTotalRow());
};

scwin.f_DeleteRow = function() {
    ds_Present.removeRow(ds_Present.getRowPosition());
    spa_totalRow.setValue(ds_Present.getTotalRow());
};

scwin.f_AllDeleteRow = function() {
    ds_Present.removeAll();
    spa_totalRow.setValue(ds_Present.getTotalRow());
};

scwin.f_UndoRow = function() {
    ds_Present.undoRow(ds_Present.getRowPosition());
};

scwin.btn_allDeleteRow_onclick = function(e) {
    scwin.f_AllDeleteRow();
};

scwin.btn_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.f_Save = async function() {
    if (ds_Present.isUpdated() == false) {
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    let chk1 = await $c.gus.cfValidate([ed_adptDt, lc_wrkPlCd]);
    if (!chk1) {
        return false;
    }

    let chk2 = await $c.gus.cfValidate([gr_InIntendInformation]);
    if (chk2) {
        let chk3 = await $c.win.confirm(MSG_CM_CRM_001);
        if (chk3 == true) {
            for (let i = 0; i < ds_Present.getRowCount(); i++) {
                ds_Present.setCellData(i, "adptDt", ed_adptDt.getValue());
                ds_Present.setCellData(i, "wrkPlCd", lc_wrkPlCd.getValue());
            }
            await $c.sbm.execute(sbm_save);
        }
    }
};

scwin.sbm_save_submitdone = async function(e) {
    await $c.gus.cfAlertMsg("성공적으로 저장되었습니다");
    $c.gus.cfEnableObjects([ed_adptDt, lc_wrkPlCd]);
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.f_grdHeiht = function(gridNm, size) {
    let strHeight = gridNm.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gridNm.style.height = intHeight + "px";
    }
};

scwin.f_runExcel = async function() {
    let totCnt = ds_Present.getRowCount();
    let fileName = "크나우프 재고_" + lc_wrkPlCd.getText() + "_" + ed_adptDt.getValue();

    if (totCnt != 0) {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            $c.data.downloadGridViewExcel(gr_InIntendInformation, {"fileName": fileName + ".xlsx", "sheetName": fileName});
        }
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

scwin.f_CheckFileExt = function(ext, path) {
    ext = ext.toUpperCase();
    path = path.toUpperCase();
    let elen = ext.length;
    let flen = path.length;
    return (ext == path.substring((flen - elen), flen));
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, "", "T", "T");
    } else {
        scwin.f_openCommonPopUp(disGubun, "", pVal, "T", "T");
    }
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([ed_adptDt, lc_wrkPlCd, ed_commCd]);
    ed_adptDt.setValue(scwin.strFromDate);
    ed_adptDt.setFocus();
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;

    switch (disGubun) {
        case 1:
            rtnList = $c.gus.cfCommonPopUp("retrieveCommGoodsInfo", pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
            $c.gus.cfSetReturnValue(rtnList, ed_commCd, txt_commNm);
            break;
        default:
            return;
    }
};

scwin.f_Import = async function() {
    let chkValid = await $c.gus.cfValidate([ed_adptDt]);
    if (!chkValid) {
        return;
    }
    if (lc_wrkPlCd.getValue() == "") {
        await $c.win.alert("작업장은 필수 입력 항목입니다.");
        return;
    }
    let wrkPlCd = lc_wrkPlCd.getText();
    let msg = "";
    let adptDt = ed_adptDt.getValue();
    msg = adptDt.substring(0, 4) + "년 " + adptDt.substring(4, 6) + "월 " + adptDt.substring(6, 8) + "일 " + wrkPlCd + " 재고업로드 하시겠습니까?";

    let chkConfirm = await $c.win.confirm(msg);
    if (!chkConfirm) {
        return;
    }

    // TODO: inputF (INPUTFILE ActiveX) 기반 CSV 파일 업로드 로직은 WebSquare 파일 업로드 컴포넌트로 대체 필요
    let inputFileName = "";
    // TODO: WebSquare 파일 선택 다이얼로그로 대체 — inputF.Open() → WebSquare 파일 업로드 API
    let inputFileLength = inputFileName.length;
    let fileExtendNameCheck = inputFileName.substring((inputFileLength - 3), inputFileLength);

    if (fileExtendNameCheck.toUpperCase() != "CSV") {
        await $c.gus.cfAlertMsg("파일이 CSV인 것만 Import가 가능합니다.\n엑셀 파일을 CSV로 변환 하시어 Import하시기 바랍니다.");
    }

    if (inputFileName == "") {
        return;
    }

    ds_upSellPlan.removeAll();
    ds_Present.removeAll();
    ds_tempSellPlan.removeAll();

    // TODO: ds_upSellPlan.Reset() — CSV 파일 로딩은 WebSquare 파일 업로드 + 서버 파싱으로 대체 필요

    for (let i = 0; i < ds_upSellPlan.getRowCount(); i++) {
        for (let j = 0; j < 15; j++) {
            let colId = ds_upSellPlan.getColumnID(j);
            ds_upSellPlan.setCellData(i, colId, scwin.f_DataFomatChg(ds_upSellPlan.getCellData(i, colId)));
        }
    }

    // TODO: ds_tempSellPlan.ImportData — GAUCE ImportData/ExportData는 WebSquare에서 직접 대응 불가, 서버 파싱 로직으로 대체 필요
    let upRowCount = ds_upSellPlan.getRowCount();
    for (let i = 3; i < upRowCount; i++) {
        let srcRow = i;
        ds_tempSellPlan.insertRow(ds_tempSellPlan.getRowCount());
        let tgtRow = ds_tempSellPlan.getRowCount() - 1;
        let colCount = ds_tempSellPlan.getColumnCount();
        for (let c = 0; c < colCount; c++) {
            let cid = ds_tempSellPlan.getColumnID(c);
            ds_tempSellPlan.setCellData(tgtRow, cid, ds_upSellPlan.getCellData(srcRow, cid));
        }
    }

    if (ds_upSellPlan.getRowCount() > 0) {
        let lastRow = ds_upSellPlan.getRowCount() - 1;
        let firstColId = ds_upSellPlan.getColumnID(0);
        if (ds_upSellPlan.getCellData(lastRow, firstColId) == "합계") {
            $c.gus.cfProgressWinClose();
            await $c.gus.cfAlertMsg("업로드 CVS 파일의 형식이 잘못되었습니다." +
                "\n사용하신 CVS파일의 마지막 합계행을 제거하고," +
                "\n다시 사용하시길 바랍니다.");
            return;
        }
    }

    for (let i = 0; i < ds_tempSellPlan.getRowCount(); i++) {
        ds_Present.insertRow(ds_Present.getRowCount());
        let row = ds_Present.getRowCount() - 1;

        ds_Present.setCellData(row, "prdtMil", ds_tempSellPlan.getCellData(i, "prdtMil"));
        ds_Present.setCellData(row, "seq", ds_tempSellPlan.getCellData(i, "seq"));
        ds_Present.setCellData(row, "clntCommCd", ds_tempSellPlan.getCellData(i, "clntCommCd"));
        ds_Present.setCellData(row, "clntCommNm", ds_tempSellPlan.getCellData(i, "clntCommNm"));
        ds_Present.setCellData(row, "commCd", ds_tempSellPlan.getCellData(i, "commCd"));
        ds_Present.setCellData(row, "qtyUnit", ds_tempSellPlan.getCellData(i, "qtyUnit"));

        ds_Present.setCellData(row, "orgQty", ds_tempSellPlan.getCellData(i, "orgQty"));
        ds_Present.setCellData(row, "damQty", ds_tempSellPlan.getCellData(i, "damQty"));
        ds_Present.setCellData(row, "trialQty", ds_tempSellPlan.getCellData(i, "trialQty"));
        ds_Present.setCellData(row, "disuseQty", ds_tempSellPlan.getCellData(i, "disuseQty"));
        ds_Present.setCellData(row, "totQty", ds_tempSellPlan.getCellData(i, "totQty"));

        ds_Present.setCellData(row, "warpQty", ds_tempSellPlan.getCellData(i, "warpQty"));
        ds_Present.setCellData(row, "rmk", ds_tempSellPlan.getCellData(i, "rmk"));

        ds_Present.setCellData(row, "clntQty", ds_tempSellPlan.getCellData(i, "clntQty"));
        ds_Present.setCellData(row, "differQty", ds_tempSellPlan.getCellData(i, "differQty"));
        ds_Present.setCellData(row, "diffCause", ds_tempSellPlan.getCellData(i, "diffCause"));

        ds_Present.setCellData(row, "adptDt", ed_adptDt.getValue());
        ds_Present.setCellData(row, "wrkPlCd", lc_wrkPlCd.getValue());

        if (ds_tempSellPlan.getCellData(i, "clntCommCd") == "") {
            $c.gus.cfProgressWinClose();
            await $c.gus.cfAlertMsg("업로드 CVS 파일의 데이터가 잘못되었습니다." + "\n[" + (i + 1) + "] 번째 행의 [품명코드] 값이 없습니다.\n사용하신 CVS파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다.");
            return;
        }
    }

    scwin.hid_adptDt = ed_adptDt.getValue();
    ds_tempSellPlan.removeAll();
    spa_totalRow.setValue(ds_Present.getRowCount());
};

scwin.f_DataFomatChg = function(value) {
    let temp = new String();
    temp = value;
    temp = temp.replace(/\'/gi, "");
    temp = temp.replace(/,/gi, "");
    temp = temp.replace(/ /gi, "");
    return temp;
};

scwin.gr_InIntendInformation_ontextimageclick = function(rowIndex, columnIndex, columnId) {
    let rtnList = new Array();
    let addCol = new Array();
    let clntCommCd = "";

    if (columnId == "clntCommNm") {
        let gubun = ",,,T3";
        rtnList = $c.gus.cfCommonPopUp("retrieveCommGoodsInfo",
            ds_Present.getCellData(rowIndex, "commCd"),
            "",
            "T",
            "3",
            "품목코드,품명,거래처품목코드",
            "105,190,70",
            "4,5,6,7,8,9,10",
            gubun,
            "440",
            "500",
            null,
            null,
            null,
            "F",
            "품목/품명,품명코드,품명"
        );
        $c.gus.cfSetGridReturnValue(rtnList, ds_Present, rowIndex, "commCd", "clntCommNm", addCol);
        clntCommCd = rtnList[9] + "";
        ds_Present.setCellData(rowIndex, "clntCommCd", clntCommCd);
    }
};

scwin.gr_InIntendInformation_oncellclick = function(rowIndex, columnIndex, columnId) {
    if (columnId == "clntCommNm") {
        if (ds_Present.getRowStatus(rowIndex) == "C") {
            gr_InIntendInformation.setColumnProp("clntCommNm", "readOnly", false);
        } else {
            gr_InIntendInformation.setColumnProp("clntCommNm", "readOnly", true);
        }
    }
};

scwin.ed_commCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_commCd, txt_commNm, 3);
};

scwin.decode_differQty = function(data) {
    return $c.gus.decode(data,
        "0", "black",
        "red"
    );
};
